import React, { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import Navbar from "../components/Navbar";

function Landing() {
  const navigate = useNavigate();

  useEffect(() => {
    document.body.style.overflow = "hidden";
    return () => (document.body.style.overflow = "auto");
  }, []);

  const handleContinue = () => {
    localStorage.removeItem("role");
    navigate("/login");
  };

  return (
    <div className="landing-page">
      <Navbar />

      {/* HERO SECTION */}
      <section className="flickr-landing">
        <div className="flickr-content">

          {/* Badge */}
          <span className="flickr-tagline animate-tagline">
            AI-powered Retail Intelligence
          </span>

          {/* Title */}
          <h1 className="flickr-title animate-title">
            Welcome to <span className="heading">RetailVision</span>
          </h1>

          {/* Subtitle */}
          <p className="flickr-tagline animate-tagline">
            Smarter inventory. Clearer decisions.
          </p>

          {/* Description */}
          <p className="flickr-support animate-support">
            Forecast demand, optimize stock, and gain actionable insights —
            all from a single intelligent dashboard built for modern retailers.
          </p>

          {/* CTA */}
          <button
            className="flickr-cta-group animate-cta"
            onClick={handleContinue}
          >
            Continue to Login
          </button>

          <button
            className="flickr-cta-group animate-cta"
            onClick={() => navigate("/signup")}
          >
            Create Account
          </button>

          {/* TRUST STRIP */}
          <div style={{ marginTop: "32px", fontSize: "14px" }}>
            <div>30% Less Stock Waste</div>
            <div>2× Faster Decisions</div>
            <div>AI Sales Suggestions</div>
          </div>

        </div>
      </section>

      {/* FOOTER */}
      <footer className="footer">
        © 2026 RetailVision • Privacy • Terms
      </footer>
    </div>
  );
}

export default Landing;
